package com.trademaster.ims.mobile.reviews.service;
import com.trademaster.ims.mobile.auth.service.CustomerAuthException;import com.trademaster.ims.mobile.checkout.model.*;import com.trademaster.ims.mobile.checkout.repository.*;import com.trademaster.ims.mobile.notifications.service.CustomerNotificationService;import com.trademaster.ims.mobile.reviews.dto.ReviewDtos.*;import com.trademaster.ims.mobile.reviews.model.CustomerProductReview;import com.trademaster.ims.mobile.reviews.repository.CustomerProductReviewRepository;import com.trademaster.ims.model.Product;import com.trademaster.ims.repository.ProductRepository;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import org.springframework.util.StringUtils;import java.math.*;import java.time.LocalDate;import java.util.*;
@Service @Transactional public class CustomerReviewService{private final CustomerProductReviewRepository reviews;private final CustomerOrderRepository orders;private final CustomerOrderItemRepository items;private final ProductRepository products;@Autowired(required=false)private CustomerNotificationService notifications;public CustomerReviewService(CustomerProductReviewRepository r,CustomerOrderRepository o,CustomerOrderItemRepository i,ProductRepository p){reviews=r;orders=o;items=i;products=p;}
@Transactional(readOnly=true)public ReviewSummaryResponse summary(Long productId){product(productId);Double avg=reviews.averageApproved(productId);long count=reviews.countByProductIdAndStatus(productId,CustomerProductReview.Status.APPROVED);return new ReviewSummaryResponse(productId,avg==null?BigDecimal.ZERO:BigDecimal.valueOf(avg).setScale(1,RoundingMode.HALF_UP),count);} 
@Transactional(readOnly=true)public List<ReviewResponse> productReviews(Long productId){product(productId);return reviews.findByProductIdAndStatusOrderByCreatedAtDesc(productId,CustomerProductReview.Status.APPROVED).stream().map(this::dto).toList();}
@Transactional(readOnly=true)public List<ReviewResponse> my(long account){return reviews.findByAccountIdOrderByCreatedAtDesc(account).stream().map(this::dto).toList();}
@Transactional(readOnly=true)public List<ReviewableItemResponse> reviewable(long account,String orderNumber){CustomerOrder o=orders.findByOrderNumberAndAccountId(orderNumber,account).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found."));boolean delivered=o.getStatus()==CustomerOrder.OrderStatus.DELIVERED;return items.findByOrderIdOrderByIdAsc(o.getId()).stream().map(i->{Optional<CustomerProductReview>r=reviews.findByAccountIdOrderByCreatedAtDesc(account).stream().filter(x->Objects.equals(x.getOrderItemId(),i.getId())&&Objects.equals(x.getProductId(),i.getProductId())).findFirst();return new ReviewableItemResponse(o.getOrderNumber(),i.getId(),i.getProductId(),i.getProductName(),i.getVariationName(),i.getImageUrl(),delivered,r.isPresent(),r.map(CustomerProductReview::getReviewNumber).orElse(null),r.map(x->x.getStatus().name()).orElse(null));}).toList();}
public ReviewResponse create(long account,Long productId,ReviewRequest q){Product p=product(productId);CustomerOrder o=orders.findByOrderNumberAndAccountId(q.orderNumber(),account).orElseThrow(()->err(HttpStatus.NOT_FOUND,"ORDER_NOT_FOUND","Order was not found."));if(o.getStatus()!=CustomerOrder.OrderStatus.DELIVERED)throw err(HttpStatus.CONFLICT,"ORDER_NOT_DELIVERED","Reviews are available only after delivery.");CustomerOrderItem item=items.findByOrderIdOrderByIdAsc(o.getId()).stream().filter(i->Objects.equals(i.getId(),q.orderItemId())).findFirst().orElseThrow(()->err(HttpStatus.BAD_REQUEST,"ORDER_ITEM_INVALID","Selected item does not belong to this order."));if(!Objects.equals(item.getProductId(),productId))throw err(HttpStatus.BAD_REQUEST,"PRODUCT_NOT_PURCHASED","This product was not purchased in the selected order item.");if(reviews.existsByAccountIdAndOrderItemIdAndProductId(account,item.getId(),productId))throw err(HttpStatus.CONFLICT,"REVIEW_ALREADY_EXISTS","You already reviewed this delivered order item.");CustomerProductReview r=new CustomerProductReview();r.setReviewNumber(number());r.setAccountId(account);r.setProductId(productId);r.setOrderNumber(o.getOrderNumber());r.setOrderItemId(item.getId());r.setRating(q.rating());r.setTitle(clean(q.title()));r.setComment(required(q.comment()));r.setStatus(CustomerProductReview.Status.APPROVED);r=reviews.save(r);if(notifications!=null)notifications.reviewSubmitted(account,r.getReviewNumber(),p.getProductName());return dto(r,p);} 
public ReviewResponse update(long account,String reviewNumber,ReviewUpdateRequest q){CustomerProductReview r=reviews.findByReviewNumberAndAccountId(reviewNumber,account).orElseThrow(()->err(HttpStatus.NOT_FOUND,"REVIEW_NOT_FOUND","Review was not found."));if(q.rating()!=null)r.setRating(q.rating());if(q.title()!=null)r.setTitle(clean(q.title()));if(q.comment()!=null)r.setComment(required(q.comment()));r.setStatus(CustomerProductReview.Status.APPROVED);r=reviews.save(r);return dto(r);} 
public ReviewResponse moderate(String reviewNumber,ModerationRequest q){CustomerProductReview r=reviews.findByReviewNumber(reviewNumber).orElseThrow(()->err(HttpStatus.NOT_FOUND,"REVIEW_NOT_FOUND","Review was not found."));CustomerProductReview.Status s;try{s=CustomerProductReview.Status.valueOf(q.status().trim().toUpperCase(Locale.ROOT));}catch(Exception e){throw err(HttpStatus.BAD_REQUEST,"INVALID_REVIEW_STATUS","Unsupported review status.");}r.setStatus(s);r.setModerationNote(clean(q.note()));r=reviews.save(r);if(notifications!=null){if(s==CustomerProductReview.Status.APPROVED)notifications.reviewApproved(r.getAccountId(),r.getReviewNumber());if(s==CustomerProductReview.Status.REJECTED)notifications.reviewRejected(r.getAccountId(),r.getReviewNumber());}return dto(r);} 
private ReviewResponse dto(CustomerProductReview r){return dto(r,products.findById(r.getProductId()).orElse(null));}private ReviewResponse dto(CustomerProductReview r,Product p){return new ReviewResponse(r.getReviewNumber(),r.getProductId(),p==null?"Product":p.getProductName(),"Verified customer",r.getOrderNumber(),r.getRating(),r.getTitle(),r.getStatus()==CustomerProductReview.Status.REJECTED?null:r.getComment(),r.getStatus().name(),r.getCreatedAt(),r.getUpdatedAt());}
private Product product(Long id){return products.findByIdAndStatus(id,Product.ProductStatus.ACTIVE).orElseThrow(()->err(HttpStatus.NOT_FOUND,"PRODUCT_NOT_FOUND","Product is unavailable."));}private String number(){String n;do{n="REV-"+LocalDate.now().toString().replace("-","")+"-"+UUID.randomUUID().toString().substring(0,8).toUpperCase(Locale.ROOT);}while(reviews.existsByReviewNumber(n));return n;}private String clean(String s){return s==null?null:s.replaceAll("<[^>]*>","").trim();}private String required(String s){String v=clean(s);if(!StringUtils.hasText(v))throw err(HttpStatus.BAD_REQUEST,"VALIDATION_ERROR","Review comment is required.");return v;}private CustomerAuthException err(HttpStatus s,String c,String m){return new CustomerAuthException(s,c,m);} }